={
  "messages": [
    ...($('Build System Prompt').item.json.sessionMessages || []),
    { "role": "user", "content": $('Build System Prompt').item.json.userMessage, "timestamp": new Date().toISOString() },
    { "role": "assistant", "content": $input.item.json.output, "timestamp": new Date().toISOString() }
  ],
  "userId": $('Build System Prompt').item.json.userId,
  "userRole": $('Build System Prompt').item.json.userRole
}
